;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.ftm-log-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:20px}\n.ftm-log-item{display:flex;gap:16px;align-items:flex-start;background:#fff;border-radius:12px;padding:20px}\n.ftm-log-icon{width:40px;height:40px;border-radius:8px;background:rgba(180,83,9,0.1);display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.ftm-log-icon svg{stroke:#b45309}\n.ftm-log-item-label{font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#000864;margin-bottom:2px}\n.ftm-log-item-value{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:400;color:#333;line-height:1.5}\n\n.et_pb_section .ftm-log-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-log-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .ftm-log-item-label,.et_pb_section .ftm-log-item-value{-webkit-font-smoothing:auto !important}\n\n@media(max-width:768px){\n  .ftm-log-grid{grid-template-columns:1fr}\n  .ftm-log-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-log-section *{transition:none !important}}\n/* === REGISTRATION CTA === */\n.ftm-reg-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:80px 24px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-reg-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.ftm-reg-section>*{position:relative;z-index:2}\n.ftm-reg-section h2{font-family:\'Noto Sans\',sans-serif;font-size:40px;font-weight:700;color:#fff;margin:0 0 16px;padding:0}\n.ftm-reg-meta{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:rgba(255,255,255,0.85);margin:0 0 32px;padding:0}\n.ftm-reg-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#fff;background:#b45309;padding:20px 48px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(180,83,9,0.4)}\n.ftm-reg-cta:hover{background:rgb(195,117,58);transform:translateY(-2px);box-shadow:0 8px 24px rgba(180,83,9,0.3)}\n.ftm-reg-secondary{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:rgba(255,255,255,0.85);margin-top:24px;padding:0}\n.ftm-reg-secondary a{color:#fff;text-decoration:underline;transition:color 0.3s ease}\n.ftm-reg-secondary a:hover{color:#fff}\n\n.et_pb_section .ftm-reg-section h2{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-reg-cta{-webkit-font-smoothing:auto !important;line-height:28.8px !important}\n.et_pb_section .ftm-reg-meta,.et_pb_section .ftm-reg-secondary{-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n@media(max-width:768px){\n  .ftm-reg-section h2{font-size:32px}\n  .ftm-reg-cta{width:100%;justify-content:center;padding:16px 32px;font-size:16px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-reg-section *{transition:none !important}}\n/* === RELATED EVENTS === */\n.ftm-rel-section{background:#F5F7FA;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-rel-inner{max-width:1100px;margin:0 auto}\n.ftm-rel-label{display:block;text-align:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#b45309;margin-bottom:16px}\n.ftm-rel-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;text-align:center;line-height:1.25;margin:0 0 16px;padding:0}\n.ftm-rel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.ftm-rel-card{background:#fff;border-radius:16px;overflow:hidden;transition:transform 0.3s ease,box-shadow 0.3s ease}\n.ftm-rel-card:hover{transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,0.08)}\n.ftm-rel-card-border{height:4px}\n.ftm-rel-card-body{padding:28px}\n.ftm-rel-badge{display:inline-block;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;padding:4px 12px;border-radius:50px;margin-bottom:12px}\n.ftm-rel-card h3{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;line-height:1.4;margin:0 0 16px;padding:0}\n.ftm-rel-meta{display:flex;flex-direction:column;gap:8px;margin-bottom:16px}\n.ftm-rel-meta-item{display:flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#5b6b80}\n.ftm-rel-meta-item svg{flex-shrink:0;stroke:#94a3b8}\n.ftm-rel-link{display:inline-flex;align-items:center;gap:4px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;text-decoration:none;transition:opacity 0.3s ease}\n.ftm-rel-link:hover{opacity:0.8}\n\n.et_pb_section .ftm-rel-title{-webkit-font-smoothing:auto !important;line-height:1.25 !important;margin:0 0 16px !important;padding:0 !important}\n.et_pb_section .ftm-rel-label{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .ftm-rel-card h3{-webkit-font-smoothing:auto !important;margin:0 0 16px !important;padding:0 !important}\n\n@media(max-width:768px){\n  .ftm-rel-grid{grid-template-columns:1fr}\n  .ftm-rel-title{font-size:28px}\n}\n@media(prefers-reduced-motion:reduce){.ftm-rel-card{transition:none !important}}\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Event Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-hero-section">\n  <div class="ftm-hero-superd" aria-hidden="true"></div>\n  <a href="/news/" class="ftm-hero-back">\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>\n    Back to News &amp; Events\n  </a>\n  <span class="ftm-hero-badge">Factory Visit</span>\n  <h1>Live Factory Tour: See DigiWin MES in Action</h1>\n  <p class="ftm-hero-subtitle">Walk the shop floor of a real factory running DigiWin MES. See how production data flows from machines to management dashboards in real time.</p>\n\n  <div class="ftm-hero-facts">\n    \n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">May 8, 2026</div>\n        <div class="ftm-hero-fact-label">Thursday</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">10:00 – 15:00</div>\n        <div class="ftm-hero-fact-label">Half Day</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0118 0z"/><circle cx="12" cy="10" r="3"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">EEC Industrial Zone</div>\n        <div class="ftm-hero-fact-label">Thailand</div>\n      </div>\n\n      <div class="ftm-hero-fact">\n        <div class="ftm-hero-fact-icon">\n          <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n        </div>\n        <div class="ftm-hero-fact-value">20 Visitors</div>\n        <div class="ftm-hero-fact-label">Limited for Safety</div>\n      </div>\n  </div>\n\n  <a href="#register" class="ftm-hero-cta">\n    Request Your Visit\n    <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="16" height="16"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n  </a>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"The Problem: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-prob-section">\n  <div class="ftm-prob-inner">\n    <span class="ftm-prob-label">The Challenge</span>\n    <h2 class="ftm-prob-title">Seeing Is Believing — Screenshots Don\'t Replace Shop Floor Reality</h2>\n  </div>\n  <div class="ftm-prob-body">\n    \n    <p>Every software vendor shows polished demo screens. Carefully curated dashboards with perfect data, running on a demo server somewhere, operated by a sales engineer who knows exactly which buttons to click. It looks great in a meeting room. But what matters is how the system works on an actual production floor — with real machines, real operators, and real problems happening in real time.</p>\n\n    <p>The gap between a demo environment and a live factory is where most MES implementations fail. Operators who struggle with the interface. Data that doesn\'t flow because a sensor was misconfigured. Reports that look different when they\'re generated from actual production chaos instead of clean sample data. <strong>You can\'t evaluate these things from a conference room.</strong></p>\n\n    <p>This factory visit gives you unfiltered access. Walk the production lines and see the screens operators actually use — not a curated demo. Ask workers directly about their experience with the system. Watch data flow live from CNC machines to the management dashboard and see how long it actually takes. This is the reality check that separates confident decisions from expensive guesses.</p>\n    \n    \n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Outcomes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-out-section">\n  <div class="ftm-out-inner">\n    <span class="ftm-out-label">Visit Outcomes</span>\n    <h2 class="ftm-out-title">What You\'ll Take Away from This Visit</h2>\n    <div class="ftm-out-grid">\n      \n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M2 20h20M6 20V10l4-6h4l4 6v10"/><path d="M6 14h12"/></svg>\n      </div>\n      <h3>See a live MES implementation on a real production floor</h3>\n      <p>Not a demo environment, not a simulation — a working factory with real production orders running through DigiWin MES right now.</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M17 21v-2a4 4 0 00-4-4H5a4 4 0 00-4-4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 00-3-3.87"/><path d="M16 3.13a4 4 0 010 7.75"/></svg>\n      </div>\n      <h3>Observe how operators interact with the system during actual production</h3>\n      <p>Watch real operators using MES terminals on the shop floor — see the interface they use, how they report production, and how they handle exceptions.</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z"/></svg>\n      </div>\n      <h3>Ask direct questions to factory staff about their experience</h3>\n      <p>No sales filter. Talk directly to the plant manager, IT team, and line operators about what worked, what didn\'t, and what they\'d change.</p>\n    </div>\n\n    <div class="ftm-out-card">\n      <div class="ftm-out-icon">\n        <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="24" height="24"><rect x="4" y="2" width="16" height="20" rx="2"/><line x1="8" y1="6" x2="16" y2="6"/><line x1="8" y1="10" x2="16" y2="10"/><line x1="8" y1="14" x2="12" y2="14"/></svg>\n      </div>\n      <h3>Understand the practical requirements for your own MES deployment</h3>\n      <p>Infrastructure, network, operator training, change management — learn what it actually takes from the people who\'ve already done it.</p>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Agenda: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-agen-section">\n  <div class="ftm-agen-inner">\n    <span class="ftm-agen-label">Tour Agenda</span>\n    <h2 class="ftm-agen-title">A Structured Visit — Not a Sales Tour</h2>\n    <p class="ftm-agen-subtitle">Every stop is designed around what you need to evaluate — not what we want to showcase.</p>\n  </div>\n  <div class="ftm-agen-timeline">\n    \n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">10:00 – 10:30</div>\n      <div class="ftm-agen-content">\n        <h3>Arrival & Safety Briefing</h3>\n        <p>Welcome, introductions, safety equipment distribution, and an overview of the factory\'s MES implementation journey.</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">10:30 – 11:30</div>\n      <div class="ftm-agen-content">\n        <h3>Factory Floor Tour — Production Lines with Live MES</h3>\n        <p>Walk the production lines and see DigiWin MES running on actual workstations. Watch operators report production, observe machine data collection, and see how exceptions are handled in real time.</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">11:30 – 12:00</div>\n      <div class="ftm-agen-content">\n        <h3>Management Dashboard Room — Real-Time Data in Action</h3>\n        <p>See how the data you just watched being collected on the shop floor appears on management dashboards — OEE, production progress, quality metrics, all updating live.</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item ftm-agen-item--break">\n      <div class="ftm-agen-time">12:00 – 13:00</div>\n      <div class="ftm-agen-content">\n        <h3>Networking Lunch with Factory Management</h3>\n        \n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">13:00 – 14:00</div>\n      <div class="ftm-agen-content">\n        <h3>Q&A with Plant Manager & IT Team</h3>\n        <p>Open session to ask anything — implementation timeline, challenges they faced, operator adoption, integration with existing systems, and the real costs involved.</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">14:00 – 14:45</div>\n      <div class="ftm-agen-content">\n        <h3>Implementation Lessons Learned — What They\'d Do Differently</h3>\n        <p>The factory team shares their honest retrospective — what went well, what surprised them, and the advice they\'d give to someone starting the same journey.</p>\n      </div>\n    </div>\n\n    <div class="ftm-agen-item">\n      <div class="ftm-agen-time">14:45 – 15:00</div>\n      <div class="ftm-agen-content">\n        <h3>Wrap-Up & Next Steps</h3>\n        <p>Summary of key takeaways, individual questions, and guidance on your next steps toward evaluating MES for your factory.</p>\n      </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Who Should Attend: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-per-section">\n  <div class="ftm-per-inner">\n    <span class="ftm-per-label">Who This Is For</span>\n    <h2 class="ftm-per-title">Is This Visit Right for You?</h2>\n    <div class="ftm-per-grid">\n      \n    <div class="ftm-per-card">\n      <div class="ftm-per-accent"></div>\n      <div class="ftm-per-body">\n        <div class="ftm-per-role">Factory Owner / Managing Director</div>\n        <span class="ftm-per-size">Considering MES Investment</span>\n        <p class="ftm-per-desc">You\'ve seen the presentations and read the brochures, but you need to see MES working in a real factory before you commit budget. You want to understand what this investment actually looks like on the shop floor — not just on slides.</p>\n        <p class="ftm-per-quote">"I need to see this working in a real factory before I commit budget."</p>\n      </div>\n    </div>\n\n    <div class="ftm-per-card">\n      <div class="ftm-per-accent"></div>\n      <div class="ftm-per-body">\n        <div class="ftm-per-role">Operations / IT Manager</div>\n        <span class="ftm-per-size">Evaluating MES Solutions</span>\n        <p class="ftm-per-desc">You\'ll be the one implementing and maintaining the system. You need to understand the practical reality — network requirements, operator training, integration complexity, and the day-to-day experience of running MES in production.</p>\n        <p class="ftm-per-quote">"I want to understand the practical reality of MES — not just the sales pitch."</p>\n      </div>\n    </div>\n    </div>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Proof & Social Signal: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="ftm-prf-section">\n  <div class="ftm-prf-inner">\n    <span class="ftm-prf-label">Why DigiWin Events</span>\n    <h2 class="ftm-prf-title">Learn from the Team That\'s Done This 100+ Times</h2>\n    <div class="ftm-prf-stats-bar">\n      \n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">100+</div>\n      <div class="ftm-prf-stat-label">Thai Implementations</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">44</div>\n      <div class="ftm-prf-stat-label">Years Manufacturing ERP</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">95%</div>\n      <div class="ftm-prf-stat-label">Contract Renewal Rate</div>\n    </div>\n\n    <div class="ftm-prf-stat">\n      <div class="ftm-prf-stat-value">50+</div>\n      <div class="ftm-prf-stat-label">Thai Team Members</div>\n    </div>\n    </div>\n    <p class="ftm-prf-text">DigiWin has been helping Thai manufacturers digitize their shop floors for 8 years. This factory visit gives you direct access to one of those implementations — the same systems, the same team, and the same approach we bring to every MES project.</p>\n  </div>\n</div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Logistics: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexW