DELETE FROM wp_postmeta WHERE post_id = 100755 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100755, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === EVENT HERO === */\n.ftm-hero-section{background:linear-gradient(165deg,#0f1419 0%,#1a2632 40%,#000864 100%);padding:140px 24px 80px;text-align:center;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-hero-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.ftm-hero-section>*{position:relative;z-index:2}\n.ftm-hero-back{display:inline-flex;align-items:center;gap:6px;font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:500;color:rgba(255,255,255,0.85);text-decoration:none;margin-bottom:24px;transition:color 0.3s ease}\n.ftm-hero-back:hover{color:rgba(255,255,255,0.9)}\n.ftm-hero-badge{display:inline-flex;align-items:center;font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:1.5px;color:#b45309;background:rgba(180,83,9,0.15);padding:6px 18px;border:1px solid rgba(180,83,9,0.3);border-radius:50px;margin-bottom:20px}\n.ftm-hero-section h1{font-family:\'Noto Sans\',sans-serif;font-size:clamp(28px,4.5vw,44px);font-weight:700;color:#fff;line-height:1.2;max-width:800px;margin:0 auto 20px;padding:0}\n.ftm-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:rgba(255,255,255,0.85);line-height:1.7;max-width:700px;margin:0 auto 40px;padding:0}\n.ftm-hero-facts{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;max-width:700px;margin:0 auto 40px;background:rgba(255,255,255,0.05);border:1px solid rgba(255,255,255,0.1);border-radius:16px;padding:24px}\n.ftm-hero-fact{text-align:center}\n.ftm-hero-fact-icon{margin-bottom:8px}\n.ftm-hero-fact-icon svg{stroke:#b45309}\n.ftm-hero-fact-value{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff}\n.ftm-hero-fact-label{font-family:\'Noto Sans\',sans-serif;font-size:13px;color:rgba(255,255,255,0.85)}\n.ftm-hero-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;color:#fff;background:#b45309;padding:16px 40px;border-radius:12px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 20px rgba(180,83,9,0.4)}\n.ftm-hero-cta:hover{background:rgb(195,117,58);transform:translateY(-2px);box-shadow:0 8px 24px rgba(180,83,9,0.3)}\n\n.et_pb_section .ftm-hero-section h1{-webkit-font-smoothing:auto !important;line-height:1.2 !important;max-width:800px !important;margin:0 auto 20px !important;padding:0 !important}\n.et_pb_section .ftm-hero-subtitle{-webkit-font-smoothing:auto !important}\n.et_pb_section .ftm-hero-fact-value{-webkit-font-smoothing:auto !important;line-height:25.6px !important;margin-bottom:4px !important}\n.et_pb_section .ftm-hero-fact-label{-webkit-font-smoothing:auto !important;line-height:20.8px !important}\n.et_pb_section .ftm-hero-badge{-webkit-font-smoothing:auto !important;line-height:19.2px !important}\n.et_pb_section .ftm-hero-cta{-webkit-font-smoothing:auto !important;line-height:25.6px !important}\n.et_pb_section .ftm-hero-back{-webkit-font-smoothing:auto !important}\n.ftm-hero-superd{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.15;pointer-events:none;z-index:0}\n\n@media(max-width:768px){\n  .ftm-hero-section{padding:120px 20px 60px}\n  .ftm-hero-facts{grid-template-columns:repeat(2,1fr);gap:20px}\n}\n@media(max-width:480px){\n  .ftm-hero-facts{grid-template-columns:1fr}\n  .ftm-hero-cta{width:100%;justify-content:center}\n}\n@media(prefers-reduced-motion:reduce){.ftm-hero-section *{transition:none !important}}\n/* === THE PROBLEM === */\n.ftm-prob-section{background:#fff;padding:80px 24px;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.ftm-prob-inner{text-align:center;max-width:800px;margin:0 auto 40px}\n.ftm-prob-label{font-family:\'JetBrains Mono\',monospace;font-size:12px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;color:#b45309;display:block;margin-bottom:16px}\n.ftm-prob-title{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.25;margin:0 0 16px;padding:0}\n.ftm-prob-body{max-width:800px;margin:0 auto}\n.ftm-prob-body p{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#333;line-height:1.8;margin:0 0 24px;padding:0}\n.ftm-prob-body strong{font-weight:600;color:#000864}\n.ftm-prob-data-card{background:linear-gradient(135deg,#0f1419,#1a2632);border-radius:16px;padding:40px;margin:32px 0;text-align:center;position:relative;overflow:hidden}\n.ftm-prob-data-card::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E